SELECT ur.user_id AS userId, r.id AS roleId, r.role_code AS roleCode, r.role_name AS roleName FROM sys_role r INNER JOIN sys_user_role ur ON ur.role_id = r.id WHERE ur.user_id IN
#{userId}
AND ur.deleted = 0 AND r.deleted = 0 AND r.status = 1 ORDER BY ur.user_id ASC, r.sort ASC, r.id ASC
